#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

typedef uint32_t u32;
typedef uint64_t u64;

u32 g_function(u32 a, u32 b, u32 x) {
    u32 temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

u32 f_function(u32 input_val) {
    u32 x[4], y[4];
    for (int i = 0; i < 4; i++) {
        x[i] = input_val & 0xFF;
        input_val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    u32 output = 0;
    for (int i = 0; i < 4; i++) {
        output |= y[i] << (8 * i);
    }
    return output & 0xFFFFFFFF;
}

int main() {
    u32 keys[6];
    keys[4] = 0x68d473f8;
    keys[5] = 0x41d02297;

    u32 gl_a = 0x5ee2b104;
    u32 gl_b = 0x12868091;
    u32 R3_a = 0xcd55e248;  // C_a_lo ^ C_a_hi
    u32 R3_b = 0x904b2e6e;  // C_b_lo ^ C_b_hi
    u32 delta = 0x12345678;

    u32 L3_a = gl_a ^ f_function(R3_a ^ keys[5]);
    u32 L3_b = gl_b ^ f_function(R3_b ^ keys[5]);
    u32 T = R3_a ^ R3_b ^ delta;
    u32 lhs = f_function(L3_a ^ keys[4]) ^ f_function(L3_b ^ keys[4]);

    printf("Checking with known keys...\n");
    printf("  k5 = 0x%08x\n", keys[5]);
    printf("  k4 = 0x%08x\n", keys[4]);
    printf("  L3_a = 0x%08x\n", L3_a);
    printf("  L3_b = 0x%08x\n", L3_b);
    printf("  T = 0x%08x\n", T);
    printf("  lhs = 0x%08x\n", lhs);
    printf("  Match: %s\n", lhs == T ? "true" : "false");

    // Now let's verify by simulating what brute3 does
    printf("\nSimulating brute3 search...\n");

    // Precompute ALL_KEYS
    u32 ALL_KEYS[65536];
    for (int s = 0; s < 65536; s++) {
        ALL_KEYS[s] = ((u32)s * 1234567) & 0xFFFFFFFF;
    }

    // Find which seed corresponds to the actual k5
    int found_k5 = -1;
    int found_k4 = -1;
    for (int s = 0; s < 65536; s++) {
        if (ALL_KEYS[s] == keys[5]) {
            found_k5 = s;
            printf("Found k5 seed: %d\n", s);
            break;
        }
    }
    for (int s = 0; s < 65536; s++) {
        if (ALL_KEYS[s] == keys[4]) {
            found_k4 = s;
            printf("Found k4 seed: %d\n", s);
            break;
        }
    }

    // Now check if our search would find it
    for (int s5 = 0; s5 < 10; s5++) {
        u32 k5_cand = ALL_KEYS[s5];
        u32 L3_a_cand = gl_a ^ f_function(R3_a ^ k5_cand);
        u32 L3_b_cand = gl_b ^ f_function(R3_b ^ k5_cand);

        for (int s4 = 0; s4 < 10; s4++) {
            u32 k4_cand = ALL_KEYS[s4];
            u32 lhs_cand = f_function(L3_a_cand ^ k4_cand) ^ f_function(L3_b_cand ^ k4_cand);
            if (lhs_cand == T) {
                printf("  seed5=%d, seed4=%d: MATCH! k5=0x%08x, k4=0x%08x\n", s5, s4, k5_cand, k4_cand);
            }
        }
    }

    // Check specifically at the correct seeds
    if (found_k5 >= 0 && found_k4 >= 0) {
        u32 k5_cand = ALL_KEYS[found_k5];
        u32 k4_cand = ALL_KEYS[found_k4];
        u32 L3_a_cand = gl_a ^ f_function(R3_a ^ k5_cand);
        u32 L3_b_cand = gl_b ^ f_function(R3_b ^ k5_cand);
        u32 lhs_cand = f_function(L3_a_cand ^ k4_cand) ^ f_function(L3_b_cand ^ k4_cand);
        printf("\nAt correct seeds (k5=%d, k4=%d): lhs=0x%08x, T=0x%08x, match=%s\n", 
               found_k5, found_k4, lhs_cand, T, lhs_cand == T ? "true" : "false");
    }

    return 0;
}
